class Solution:
    def numberOfBoomerangs(self, points: List[List[int]]) -> int:
        ans = 0
        for x1, y1 in points:
            cnt = defaultdict(int)
            for x2, y2 in points:
                d = (x1-x2)**2 + (y1-y2)**2
                cnt[d] += 1
            for c in cnt.values():
                ans += c * (c - 1)
        return ans

