class Solution {
public:
    int numberOfBoomerangs(vector<vector<int>>& p) {
        int ans=0;
        for(auto& a:p){
            unordered_map<int,int> cnt;
            for(auto& b:p){
                int d=(a[0]-b[0])*(a[0]-b[0])+(a[1]-b[1])*(a[1]-b[1]);
                ans += 2*cnt[d]; cnt[d]++;
            }
        }
        return ans;
    }
};

