int numberOfBoomerangs(int** points, int n, int* cs) {
    int ans=0;
    for(int i=0;i<n;i++){
        int cnt[200000]={0};
        for(int j=0;j<n;j++){
            int dx=points[i][0]-points[j][0], dy=points[i][1]-points[j][1];
            int d=dx*dx+dy*dy;
            ans += 2*cnt[d+100000]; cnt[d+100000]++;
        }
    }
    return ans;
}
